// MARK: - Push Notifications

extension HybridWebViewController {

    private func handlePush(payload: [String: Any], requestId: String) {
        let action = (payload["action"] as? String) ?? "requestPermission" // requestPermission | getStatus

        let center = UNUserNotificationCenter.current()

        switch action {
        case "getStatus":
            center.getNotificationSettings { settings in
                let status: String
                switch settings.authorizationStatus {
                case .notDetermined: status = "notDetermined"
                case .denied: status = "denied"
                case .authorized: status = "authorized"
                case .provisional: status = "provisional"
                case .ephemeral: status = "ephemeral"
                @unknown default: status = "unknown"
                }
                DispatchQueue.main.async {
                    self.resolve(requestId: requestId, result: ["status": status])
                }
            }

        case "requestPermission":
            let options: UNAuthorizationOptions = [.alert, .badge, .sound]
            center.requestAuthorization(options: options) { granted, error in
                DispatchQueue.main.async {
                    if let error {
                        self.reject(requestId: requestId, code: "error", message: error.localizedDescription)
                        return
                    }
                    UIApplication.shared.registerForRemoteNotifications()
                    self.resolve(requestId: requestId, result: ["granted": granted])
                }
            }

        default:
            reject(requestId: requestId, code: "unsupported_action", message: "Unsupported push action: \(action)")
        }
    }
}

